import React, { useState, useEffect, useRef } from "react";
import { createRoot } from "react-dom/client";
import { GoogleGenAI } from "@google/genai";
import {
  Activity,
  Save,
  Plus,
  Trash2,
  FileText,
  Clock,
  User,
  MapPin,
  Stethoscope,
  Syringe,
  CheckCircle,
  AlertCircle,
  Sparkles,
  History,
  ClipboardList
} from "lucide-react";

// --- Types ---

interface UsedItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
}

interface TrolleyForm {
  id: string;
  patientName: string;
  mrn: string; // Medical Record Number
  room: string;
  timestamp: string;
  doctorName: string;
  nurseName: string;
  diagnosis: string;
  items: UsedItem[];
  narrativeNotes: string;
  isRestocked: boolean;
}

// --- Mock Data / Constants ---

const INITIAL_FORM: TrolleyForm = {
  id: "",
  patientName: "",
  mrn: "",
  room: "",
  timestamp: new Date().toISOString().slice(0, 16),
  doctorName: "",
  nurseName: "",
  diagnosis: "",
  items: [],
  narrativeNotes: "",
  isRestocked: false,
};

const COMMON_ITEMS = [
  "Epinephrine 1mg/1ml",
  "Atropine Sulfate 0.25mg",
  "Amiodarone 150mg",
  "Dobutamine",
  "Dopamine",
  "Lidocaine 2%",
  "Spuit 3cc",
  "Spuit 5cc",
  "Spuit 10cc",
  "IV Catheter 18G",
  "IV Catheter 20G",
  "IV Catheter 22G",
  "Endotracheal Tube 7.0",
  "Endotracheal Tube 7.5",
  "Electrode ECG",
  "Defibrillator Pads",
];

// --- Components ---

const App = () => {
  const [activeTab, setActiveTab] = useState<"form" | "history">("form");
  const [formData, setFormData] = useState<TrolleyForm>({ ...INITIAL_FORM, id: crypto.randomUUID() });
  const [savedLogs, setSavedLogs] = useState<TrolleyForm[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Initialize API Key safely
  const apiKey = process.env.API_KEY || ""; 

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, checked } = e.target;
    setFormData((prev) => ({ ...prev, [name]: checked }));
  };

  const addItem = (itemName: string = "") => {
    const newItem: UsedItem = {
      id: crypto.randomUUID(),
      name: itemName,
      quantity: 1,
      unit: "pcs",
    };
    setFormData((prev) => ({ ...prev, items: [...prev.items, newItem] }));
  };

  const updateItem = (id: string, field: keyof UsedItem, value: any) => {
    setFormData((prev) => ({
      ...prev,
      items: prev.items.map((item) => (item.id === id ? { ...item, [field]: value } : item)),
    }));
  };

  const removeItem = (id: string) => {
    setFormData((prev) => ({
      ...prev,
      items: prev.items.filter((item) => item.id !== id),
    }));
  };

  const handleGenerateNarrative = async () => {
    if (!apiKey) {
      showNotification("API Key missing (process.env.API_KEY)", "error");
      return;
    }

    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey });
      const model = "gemini-3-flash-preview"; 

      const prompt = `
        You are a professional medical scribe. Create a formal, clinical narrative report based on the following Emergency Trolley usage data.
        Use medical terminology. Be concise and objective.

        Data:
        Patient: ${formData.patientName} (MRN: ${formData.mrn})
        Location: ${formData.room}
        Date/Time: ${formData.timestamp}
        Doctor: ${formData.doctorName}
        Nurse: ${formData.nurseName}
        Suspected Diagnosis/Event: ${formData.diagnosis}

        Items Used:
        ${formData.items.map(i => `- ${i.name}: ${i.quantity} ${i.unit}`).join('\n')}

        Format the output as a clinical note suitable for a medical record.
      `;

      const response = await ai.models.generateContent({
        model,
        contents: prompt,
      });

      setFormData(prev => ({ ...prev, narrativeNotes: response.text }));
      showNotification("Clinical Narrative Generated", "success");
    } catch (error) {
      console.error(error);
      showNotification("Failed to generate report", "error");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    if (!formData.patientName || !formData.mrn) {
      showNotification("Patient Name and MRN are required", "error");
      return;
    }
    setSavedLogs([formData, ...savedLogs]);
    setFormData({ ...INITIAL_FORM, id: crypto.randomUUID() });
    showNotification("Log saved successfully", "success");
    setActiveTab("history");
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Toast Notification */}
      {notification && (
        <div className={`fixed top-4 right-4 z-50 px-6 py-3 rounded-lg shadow-lg text-white font-medium transition-all transform translate-y-0 ${notification.type === 'success' ? 'bg-green-600' : 'bg-red-600'}`}>
          {notification.message}
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-red-600 p-2 rounded-lg">
              <Activity className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 leading-none">Emergency Trolley</h1>
              <p className="text-xs text-gray-500 font-medium tracking-wide">USAGE LOG FORM</p>
            </div>
          </div>
          <div className="flex items-center space-x-1">
            <button
              onClick={() => setActiveTab("form")}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                activeTab === "form" ? "bg-red-50 text-red-700" : "text-gray-600 hover:bg-gray-50"
              }`}
            >
              New Log
            </button>
            <button
              onClick={() => setActiveTab("history")}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                activeTab === "history" ? "bg-red-50 text-red-700" : "text-gray-600 hover:bg-gray-50"
              }`}
            >
              History ({savedLogs.length})
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {activeTab === "form" ? (
          <div className="space-y-6">

            {/* 1. Identitas Pasien & Waktu */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex items-center">
                <User className="w-5 h-5 text-gray-500 mr-2" />
                <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Patient & Time</h2>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Patient Name</label>
                  <input
                    type="text"
                    name="patientName"
                    value={formData.patientName}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="e.g. John Doe"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Medical Record No. (MRN/RM)</label>
                  <input
                    type="text"
                    name="mrn"
                    value={formData.mrn}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="e.g. 12-34-56"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Room / Ward</label>
                  <div className="relative">
                    <MapPin className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                    <input
                      type="text"
                      name="room"
                      value={formData.room}
                      onChange={handleInputChange}
                      className="w-full pl-9 rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                      placeholder="e.g. ICU Bed 4"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Date & Time of Event</label>
                  <div className="relative">
                    <Clock className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                    <input
                      type="datetime-local"
                      name="timestamp"
                      value={formData.timestamp}
                      onChange={handleInputChange}
                      className="w-full pl-9 rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* 2. Resuscitation Team */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex items-center">
                <Stethoscope className="w-5 h-5 text-gray-500 mr-2" />
                <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Resuscitation Team & Event</h2>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Doctor in Charge</label>
                  <input
                    type="text"
                    name="doctorName"
                    value={formData.doctorName}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="Dr. Name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Nurse in Charge</label>
                  <input
                    type="text"
                    name="nurseName"
                    value={formData.nurseName}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="Nurse Name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Event / Diagnosis</label>
                  <input
                    type="text"
                    name="diagnosis"
                    value={formData.diagnosis}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="e.g. Cardiac Arrest, Respiratory Failure"
                  />
                </div>
              </div>
            </div>

            {/* 3. Items Used */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex justify-between items-center">
                <div className="flex items-center">
                  <Syringe className="w-5 h-5 text-gray-500 mr-2" />
                  <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Medication & Equipment Used</h2>
                </div>
                <div className="flex space-x-2">
                  <select 
                    className="text-sm border-gray-300 rounded-md shadow-sm focus:border-red-500 focus:ring-red-500 p-1"
                    onChange={(e) => {
                      if(e.target.value) {
                        addItem(e.target.value);
                        e.target.value = "";
                      }
                    }}
                  >
                    <option value="">+ Quick Add Item</option>
                    {COMMON_ITEMS.map(item => (
                      <option key={item} value={item}>{item}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div className="p-6">
                {formData.items.length === 0 ? (
                  <div className="text-center py-8 bg-gray-50 rounded-lg border-2 border-dashed border-gray-200">
                    <p className="text-gray-500 text-sm">No items recorded yet.</p>
                    <button 
                      onClick={() => addItem()}
                      className="mt-2 text-red-600 hover:text-red-700 text-sm font-medium flex items-center justify-center mx-auto"
                    >
                      <Plus className="w-4 h-4 mr-1" /> Add Manual Item
                    </button>
                  </div>
                ) : (
                  <div className="space-y-3">
                    <div className="grid grid-cols-12 gap-4 text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2 px-2">
                      <div className="col-span-6">Item Name</div>
                      <div className="col-span-3">Quantity</div>
                      <div className="col-span-2">Unit</div>
                      <div className="col-span-1"></div>
                    </div>
                    {formData.items.map((item) => (
                      <div key={item.id} className="grid grid-cols-12 gap-4 items-center bg-gray-50 p-2 rounded-md">
                        <div className="col-span-6">
                          <input
                            type="text"
                            value={item.name}
                            onChange={(e) => updateItem(item.id, "name", e.target.value)}
                            className="w-full bg-transparent border-0 border-b border-gray-300 focus:border-red-500 focus:ring-0 p-0 text-sm text-gray-900 placeholder-gray-400"
                            placeholder="Item Name"
                          />
                        </div>
                        <div className="col-span-3">
                          <input
                            type="number"
                            min="1"
                            value={item.quantity}
                            onChange={(e) => updateItem(item.id, "quantity", parseInt(e.target.value))}
                            className="w-full bg-white rounded border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 text-sm p-1.5"
                          />
                        </div>
                        <div className="col-span-2">
                          <input
                            type="text"
                            value={item.unit}
                            onChange={(e) => updateItem(item.id, "unit", e.target.value)}
                            className="w-full bg-transparent border-0 border-b border-gray-300 focus:border-red-500 focus:ring-0 p-0 text-sm text-gray-600"
                          />
                        </div>
                        <div className="col-span-1 text-right">
                          <button
                            onClick={() => removeItem(item.id)}
                            className="text-gray-400 hover:text-red-500 transition-colors"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    ))}
                    <button 
                      onClick={() => addItem()}
                      className="mt-4 w-full py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                    >
                      <Plus className="w-4 h-4 mr-2" /> Add Another Item
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* 4. Narrative Notes & AI */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
               <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex items-center justify-between">
                <div className="flex items-center">
                  <FileText className="w-5 h-5 text-gray-500 mr-2" />
                  <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Clinical Narrative</h2>
                </div>
                <button
                  onClick={handleGenerateNarrative}
                  disabled={isGenerating}
                  className="flex items-center space-x-2 text-xs font-semibold bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-full hover:bg-indigo-100 transition-colors border border-indigo-200"
                >
                  <Sparkles className={`w-3 h-3 ${isGenerating ? 'animate-spin' : ''}`} />
                  <span>{isGenerating ? 'Writing...' : 'Auto-Generate with AI'}</span>
                </button>
              </div>
              <div className="p-6">
                <textarea
                  name="narrativeNotes"
                  value={formData.narrativeNotes}
                  onChange={handleInputChange}
                  rows={6}
                  className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-3 border"
                  placeholder="Clinical notes about the resuscitation event..."
                />
              </div>
            </div>

            {/* 5. Verification */}
            <div className="bg-blue-50 rounded-xl p-6 flex flex-col sm:flex-row items-start sm:items-center justify-between border border-blue-100">
              <div className="flex items-start mb-4 sm:mb-0">
                <AlertCircle className="w-6 h-6 text-blue-600 mr-3 mt-1" />
                <div>
                  <h3 className="text-sm font-bold text-blue-900">Restock Verification</h3>
                  <p className="text-xs text-blue-700 mt-1">
                    Confirm that the trolley has been restocked, locked, and is ready for the next use.
                  </p>
                </div>
              </div>
              <label className="flex items-center space-x-3 bg-white px-4 py-2 rounded-lg border border-blue-200 shadow-sm cursor-pointer hover:bg-blue-50 transition-colors">
                <input
                  type="checkbox"
                  name="isRestocked"
                  checked={formData.isRestocked}
                  onChange={handleCheckboxChange}
                  className="h-5 w-5 text-blue-600 rounded border-gray-300 focus:ring-blue-500"
                />
                <span className="text-sm font-medium text-gray-700">Trolley Restocked & Locked</span>
              </label>
            </div>

            {/* Footer Action */}
            <div className="flex justify-end pt-4">
               <button
                onClick={handleSave}
                className="flex items-center px-8 py-3 bg-red-600 text-white rounded-lg shadow hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 font-medium transition-colors"
              >
                <Save className="w-5 h-5 mr-2" />
                Save & Submit Log
              </button>
            </div>

          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-gray-800 flex items-center">
                <History className="w-6 h-6 mr-2 text-gray-600" />
                Usage History
              </h2>
            </div>

            {savedLogs.length === 0 ? (
              <div className="text-center py-16 bg-white rounded-xl shadow-sm border border-gray-200">
                <ClipboardList className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900">No logs found</h3>
                <p className="text-gray-500 mt-1">Start by creating a new trolley usage log.</p>
                <button
                  onClick={() => setActiveTab("form")}
                  className="mt-6 px-4 py-2 bg-red-600 text-white rounded-md text-sm font-medium hover:bg-red-700"
                >
                  Create New Log
                </button>
              </div>
            ) : (
              <div className="grid gap-6">
                {savedLogs.map((log) => (
                  <div key={log.id} className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 transition-shadow hover:shadow-md">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h3 className="text-lg font-bold text-gray-900">{log.patientName}</h3>
                        <div className="flex items-center text-sm text-gray-500 mt-1 space-x-3">
                          <span className="bg-gray-100 px-2 py-0.5 rounded text-gray-700 font-mono text-xs">MRN: {log.mrn}</span>
                          <span className="flex items-center"><MapPin className="w-3 h-3 mr-1" /> {log.room}</span>
                          <span className="flex items-center"><Clock className="w-3 h-3 mr-1" /> {new Date(log.timestamp).toLocaleString()}</span>
                        </div>
                      </div>
                      {log.isRestocked ? (
                         <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                           <CheckCircle className="w-3 h-3 mr-1" /> Restocked
                         </span>
                      ) : (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">
                          <AlertCircle className="w-3 h-3 mr-1" /> Pending Restock
                        </span>
                      )}
                    </div>

                    <div className="border-t border-gray-100 pt-4 mt-4 grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div>
                        <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Diagnosis & Team</h4>
                        <p className="text-sm text-gray-800 mb-1"><span className="font-medium">Dx:</span> {log.diagnosis || "N/A"}</p>
                        <p className="text-sm text-gray-600"><span className="font-medium">Dr.</span> {log.doctorName} • <span className="font-medium">Ns.</span> {log.nurseName}</p>
                      </div>
                      <div>
                         <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Items Used</h4>
                         <div className="flex flex-wrap gap-2">
                            {log.items.map(item => (
                              <span key={item.id} className="inline-flex items-center px-2 py-1 rounded-md text-xs font-medium bg-gray-100 text-gray-700">
                                {item.name} <span className="ml-1 text-gray-500">x{item.quantity}</span>
                              </span>
                            ))}
                         </div>
                      </div>
                    </div>

                    {log.narrativeNotes && (
                      <div className="mt-4 bg-gray-50 p-3 rounded-lg border border-gray-100">
                        <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Clinical Note</h4>
                        <p className="text-sm text-gray-700 whitespace-pre-line">{log.narrativeNotes}</p>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

const root = createRoot(document.getElementById("root")!);
root.render(<App />);

import React, { useState, useEffect, useRef } from "react";
import { createRoot } from "react-dom/client";
import { GoogleGenAI } from "@google/genai";
import {
  Activity,
  Save,
  Plus,
  Trash2,
  FileText,
  Clock,
  User,
  MapPin,
  Stethoscope,
  Syringe,
  CheckCircle,
  AlertCircle,
  Sparkles,
  History,
  ClipboardList
} from "lucide-react";

// --- Types ---

interface UsedItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
}

interface TrolleyForm {
  id: string;
  patientName: string;
  mrn: string; // Medical Record Number
  room: string;
  timestamp: string;
  doctorName: string;
  nurseName: string;
  diagnosis: string;
  items: UsedItem[];
  narrativeNotes: string;
  isRestocked: boolean;
}

// --- Mock Data / Constants ---

const INITIAL_FORM: TrolleyForm = {
  id: "",
  patientName: "",
  mrn: "",
  room: "",
  timestamp: new Date().toISOString().slice(0, 16),
  doctorName: "",
  nurseName: "",
  diagnosis: "",
  items: [],
  narrativeNotes: "",
  isRestocked: false,
};

const COMMON_ITEMS = [
  "Epinephrine 1mg/1ml",
  "Atropine Sulfate 0.25mg",
  "Amiodarone 150mg",
  "Dobutamine",
  "Dopamine",
  "Lidocaine 2%",
  "Spuit 3cc",
  "Spuit 5cc",
  "Spuit 10cc",
  "IV Catheter 18G",
  "IV Catheter 20G",
  "IV Catheter 22G",
  "Endotracheal Tube 7.0",
  "Endotracheal Tube 7.5",
  "Electrode ECG",
  "Defibrillator Pads",
];

// --- Components ---

const App = () => {
  const [activeTab, setActiveTab] = useState<"form" | "history">("form");
  const [formData, setFormData] = useState<TrolleyForm>({ ...INITIAL_FORM, id: crypto.randomUUID() });
  const [savedLogs, setSavedLogs] = useState<TrolleyForm[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Initialize API Key safely
  const apiKey = process.env.API_KEY || ""; 

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, checked } = e.target;
    setFormData((prev) => ({ ...prev, [name]: checked }));
  };

  const addItem = (itemName: string = "") => {
    const newItem: UsedItem = {
      id: crypto.randomUUID(),
      name: itemName,
      quantity: 1,
      unit: "pcs",
    };
    setFormData((prev) => ({ ...prev, items: [...prev.items, newItem] }));
  };

  const updateItem = (id: string, field: keyof UsedItem, value: any) => {
    setFormData((prev) => ({
      ...prev,
      items: prev.items.map((item) => (item.id === id ? { ...item, [field]: value } : item)),
    }));
  };

  const removeItem = (id: string) => {
    setFormData((prev) => ({
      ...prev,
      items: prev.items.filter((item) => item.id !== id),
    }));
  };

  const handleGenerateNarrative = async () => {
    if (!apiKey) {
      showNotification("API Key hilang (process.env.API_KEY)", "error");
      return;
    }

    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey });
      const model = "gemini-3-flash-preview"; 

      const prompt = `
        Anda adalah juru tulis medis profesional. Buatlah laporan narasi klinis formal berdasarkan data pemakaian Troli Emergency berikut.
        Gunakan terminologi medis yang tepat dalam Bahasa Indonesia. Bersikaplah ringkas dan objektif.

        Data:
        Pasien: ${formData.patientName} (RM: ${formData.mrn})
        Lokasi: ${formData.room}
        Tanggal/Waktu: ${formData.timestamp}
        Dokter: ${formData.doctorName}
        Perawat: ${formData.nurseName}
        Dugaan Diagnosis/Kejadian: ${formData.diagnosis}

        Item yang Digunakan:
        ${formData.items.map(i => `- ${i.name}: ${i.quantity} ${i.unit}`).join('\n')}

        Format output sebagai catatan klinis yang sesuai untuk rekam medis.
      `;

      const response = await ai.models.generateContent({
        model,
        contents: prompt,
      });

      setFormData(prev => ({ ...prev, narrativeNotes: response.text }));
      showNotification("Narasi Klinis Berhasil Dibuat", "success");
    } catch (error) {
      console.error(error);
      showNotification("Gagal membuat laporan", "error");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    if (!formData.patientName || !formData.mrn) {
      showNotification("Nama Pasien dan No. RM wajib diisi", "error");
      return;
    }
    setSavedLogs([formData, ...savedLogs]);
    setFormData({ ...INITIAL_FORM, id: crypto.randomUUID() });
    showNotification("Log berhasil disimpan", "success");
    setActiveTab("history");
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Toast Notification */}
      {notification && (
        <div className={`fixed top-4 right-4 z-50 px-6 py-3 rounded-lg shadow-lg text-white font-medium transition-all transform translate-y-0 ${notification.type === 'success' ? 'bg-green-600' : 'bg-red-600'}`}>
          {notification.message}
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-red-600 p-2 rounded-lg">
              <Activity className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 leading-none">Troli Emergency</h1>
              <p className="text-xs text-gray-500 font-medium tracking-wide">FORMULIR LOG PEMAKAIAN</p>
            </div>
          </div>
          <div className="flex items-center space-x-1">
            <button
              onClick={() => setActiveTab("form")}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                activeTab === "form" ? "bg-red-50 text-red-700" : "text-gray-600 hover:bg-gray-50"
              }`}
            >
              Log Baru
            </button>
            <button
              onClick={() => setActiveTab("history")}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                activeTab === "history" ? "bg-red-50 text-red-700" : "text-gray-600 hover:bg-gray-50"
              }`}
            >
              Riwayat ({savedLogs.length})
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {activeTab === "form" ? (
          <div className="space-y-6">

            {/* 1. Identitas Pasien & Waktu */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex items-center">
                <User className="w-5 h-5 text-gray-500 mr-2" />
                <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Pasien & Waktu</h2>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Nama Pasien</label>
                  <input
                    type="text"
                    name="patientName"
                    value={formData.patientName}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="Contoh: Budi Santoso"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">No. Rekam Medis (RM)</label>
                  <input
                    type="text"
                    name="mrn"
                    value={formData.mrn}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="Contoh: 12-34-56"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Ruangan / Bangsal</label>
                  <div className="relative">
                    <MapPin className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                    <input
                      type="text"
                      name="room"
                      value={formData.room}
                      onChange={handleInputChange}
                      className="w-full pl-9 rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                      placeholder="Contoh: ICU Bed 4"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Tanggal & Waktu Kejadian</label>
                  <div className="relative">
                    <Clock className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                    <input
                      type="datetime-local"
                      name="timestamp"
                      value={formData.timestamp}
                      onChange={handleInputChange}
                      className="w-full pl-9 rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* 2. Resuscitation Team */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex items-center">
                <Stethoscope className="w-5 h-5 text-gray-500 mr-2" />
                <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Tim Resusitasi & Kejadian</h2>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Dokter Penanggung Jawab</label>
                  <input
                    type="text"
                    name="doctorName"
                    value={formData.doctorName}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="Nama Dokter"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Perawat Penanggung Jawab</label>
                  <input
                    type="text"
                    name="nurseName"
                    value={formData.nurseName}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="Nama Perawat"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Kejadian / Diagnosis</label>
                  <input
                    type="text"
                    name="diagnosis"
                    value={formData.diagnosis}
                    onChange={handleInputChange}
                    className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-2 border"
                    placeholder="Contoh: Henti Jantung, Gagal Napas"
                  />
                </div>
              </div>
            </div>

            {/* 3. Items Used */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
              <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex justify-between items-center">
                <div className="flex items-center">
                  <Syringe className="w-5 h-5 text-gray-500 mr-2" />
                  <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Obat & Peralatan yang Digunakan</h2>
                </div>
                <div className="flex space-x-2">
                  <select 
                    className="text-sm border-gray-300 rounded-md shadow-sm focus:border-red-500 focus:ring-red-500 p-1"
                    onChange={(e) => {
                      if(e.target.value) {
                        addItem(e.target.value);
                        e.target.value = "";
                      }
                    }}
                  >
                    <option value="">+ Tambah Cepat Item</option>
                    {COMMON_ITEMS.map(item => (
                      <option key={item} value={item}>{item}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div className="p-6">
                {formData.items.length === 0 ? (
                  <div className="text-center py-8 bg-gray-50 rounded-lg border-2 border-dashed border-gray-200">
                    <p className="text-gray-500 text-sm">Belum ada item tercatat.</p>
                    <button 
                      onClick={() => addItem()}
                      className="mt-2 text-red-600 hover:text-red-700 text-sm font-medium flex items-center justify-center mx-auto"
                    >
                      <Plus className="w-4 h-4 mr-1" /> Tambah Item Manual
                    </button>
                  </div>
                ) : (
                  <div className="space-y-3">
                    <div className="grid grid-cols-12 gap-4 text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2 px-2">
                      <div className="col-span-6">Nama Item</div>
                      <div className="col-span-3">Jumlah</div>
                      <div className="col-span-2">Satuan</div>
                      <div className="col-span-1"></div>
                    </div>
                    {formData.items.map((item) => (
                      <div key={item.id} className="grid grid-cols-12 gap-4 items-center bg-gray-50 p-2 rounded-md">
                        <div className="col-span-6">
                          <input
                            type="text"
                            value={item.name}
                            onChange={(e) => updateItem(item.id, "name", e.target.value)}
                            className="w-full bg-transparent border-0 border-b border-gray-300 focus:border-red-500 focus:ring-0 p-0 text-sm text-gray-900 placeholder-gray-400"
                            placeholder="Nama Item"
                          />
                        </div>
                        <div className="col-span-3">
                          <input
                            type="number"
                            min="1"
                            value={item.quantity}
                            onChange={(e) => updateItem(item.id, "quantity", parseInt(e.target.value))}
                            className="w-full bg-white rounded border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 text-sm p-1.5"
                          />
                        </div>
                        <div className="col-span-2">
                          <input
                            type="text"
                            value={item.unit}
                            onChange={(e) => updateItem(item.id, "unit", e.target.value)}
                            className="w-full bg-transparent border-0 border-b border-gray-300 focus:border-red-500 focus:ring-0 p-0 text-sm text-gray-600"
                          />
                        </div>
                        <div className="col-span-1 text-right">
                          <button
                            onClick={() => removeItem(item.id)}
                            className="text-gray-400 hover:text-red-500 transition-colors"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    ))}
                    <button 
                      onClick={() => addItem()}
                      className="mt-4 w-full py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                    >
                      <Plus className="w-4 h-4 mr-2" /> Tambah Item Lain
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* 4. Narrative Notes & AI */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
               <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex items-center justify-between">
                <div className="flex items-center">
                  <FileText className="w-5 h-5 text-gray-500 mr-2" />
                  <h2 className="text-sm font-semibold text-gray-800 uppercase tracking-wider">Narasi Klinis</h2>
                </div>
                <button
                  onClick={handleGenerateNarrative}
                  disabled={isGenerating}
                  className="flex items-center space-x-2 text-xs font-semibold bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-full hover:bg-indigo-100 transition-colors border border-indigo-200"
                >
                  <Sparkles className={`w-3 h-3 ${isGenerating ? 'animate-spin' : ''}`} />
                  <span>{isGenerating ? 'Menulis...' : 'Buat Otomatis dengan AI'}</span>
                </button>
              </div>
              <div className="p-6">
                <textarea
                  name="narrativeNotes"
                  value={formData.narrativeNotes}
                  onChange={handleInputChange}
                  rows={6}
                  className="w-full rounded-md border-gray-300 shadow-sm focus:border-red-500 focus:ring-red-500 sm:text-sm p-3 border"
                  placeholder="Catatan klinis tentang kejadian resusitasi..."
                />
              </div>
            </div>

            {/* 5. Verification */}
            <div className="bg-blue-50 rounded-xl p-6 flex flex-col sm:flex-row items-start sm:items-center justify-between border border-blue-100">
              <div className="flex items-start mb-4 sm:mb-0">
                <AlertCircle className="w-6 h-6 text-blue-600 mr-3 mt-1" />
                <div>
                  <h3 className="text-sm font-bold text-blue-900">Verifikasi Restock</h3>
                  <p className="text-xs text-blue-700 mt-1">
                    Konfirmasi bahwa troli telah diisi ulang, dikunci, dan siap digunakan kembali.
                  </p>
                </div>
              </div>
              <label className="flex items-center space-x-3 bg-white px-4 py-2 rounded-lg border border-blue-200 shadow-sm cursor-pointer hover:bg-blue-50 transition-colors">
                <input
                  type="checkbox"
                  name="isRestocked"
                  checked={formData.isRestocked}
                  onChange={handleCheckboxChange}
                  className="h-5 w-5 text-blue-600 rounded border-gray-300 focus:ring-blue-500"
                />
                <span className="text-sm font-medium text-gray-700">Troli Terisi & Terkunci</span>
              </label>
            </div>

            {/* Footer Action */}
            <div className="flex justify-end pt-4">
               <button
                onClick={handleSave}
                className="flex items-center px-8 py-3 bg-red-600 text-white rounded-lg shadow hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 font-medium transition-colors"
              >
                <Save className="w-5 h-5 mr-2" />
                Simpan & Kirim Log
              </button>
            </div>

          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-gray-800 flex items-center">
                <History className="w-6 h-6 mr-2 text-gray-600" />
                Riwayat Pemakaian
              </h2>
            </div>

            {savedLogs.length === 0 ? (
              <div className="text-center py-16 bg-white rounded-xl shadow-sm border border-gray-200">
                <ClipboardList className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900">Tidak ada log ditemukan</h3>
                <p className="text-gray-500 mt-1">Mulai dengan membuat log pemakaian troli baru.</p>
                <button
                  onClick={() => setActiveTab("form")}
                  className="mt-6 px-4 py-2 bg-red-600 text-white rounded-md text-sm font-medium hover:bg-red-700"
                >
                  Buat Log Baru
                </button>
              </div>
            ) : (
              <div className="grid gap-6">
                {savedLogs.map((log) => (
                  <div key={log.id} className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 transition-shadow hover:shadow-md">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h3 className="text-lg font-bold text-gray-900">{log.patientName}</h3>
                        <div className="flex items-center text-sm text-gray-500 mt-1 space-x-3">
                          <span className="bg-gray-100 px-2 py-0.5 rounded text-gray-700 font-mono text-xs">RM: {log.mrn}</span>
                          <span className="flex items-center"><MapPin className="w-3 h-3 mr-1" /> {log.room}</span>
                          <span className="flex items-center"><Clock className="w-3 h-3 mr-1" /> {new Date(log.timestamp).toLocaleString()}</span>
                        </div>
                      </div>
                      {log.isRestocked ? (
                         <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                           <CheckCircle className="w-3 h-3 mr-1" /> Sudah Restock
                         </span>
                      ) : (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">
                          <AlertCircle className="w-3 h-3 mr-1" /> Menunggu Restock
                        </span>
                      )}
                    </div>

                    <div className="border-t border-gray-100 pt-4 mt-4 grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div>
                        <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Diagnosis & Tim</h4>
                        <p className="text-sm text-gray-800 mb-1"><span className="font-medium">Dx:</span> {log.diagnosis || "N/A"}</p>
                        <p className="text-sm text-gray-600"><span className="font-medium">Dr.</span> {log.doctorName} • <span className="font-medium">Ns.</span> {log.nurseName}</p>
                      </div>
                      <div>
                         <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Item yang Digunakan</h4>
                         <div className="flex flex-wrap gap-2">
                            {log.items.map(item => (
                              <span key={item.id} className="inline-flex items-center px-2 py-1 rounded-md text-xs font-medium bg-gray-100 text-gray-700">
                                {item.name} <span className="ml-1 text-gray-500">x{item.quantity}</span>
                              </span>
                            ))}
                         </div>
                      </div>
                    </div>

                    {log.narrativeNotes && (
                      <div className="mt-4 bg-gray-50 p-3 rounded-lg border border-gray-100">
                        <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Catatan Klinis</h4>
                        <p className="text-sm text-gray-700 whitespace-pre-line">{log.narrativeNotes}</p>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

const root = createRoot(document.getElementById("root")!);
root.render(<App />);
